DROP VIEW "transit"."stop_time_instances";--> statement-breakpoint
CREATE VIEW "transit"."stop_time_instances" AS (select rt.id as "id", COALESCE(rt.trip_instance_id, st.trip_instance_id) as "trip_instance_id", COALESCE(rt.stop_time_id, st.stop_time_id) as "stop_time_id", COALESCE(rt.stop_sequence, st.stop_sequence) as "stop_sequence", COALESCE(rt.stop_id, st.stop_id) as "stop_id", st.timepoint as "timepoint", COALESCE(rt.scheduled_arrival_time, st.scheduled_arrival_time) as "scheduled_arrival_time", COALESCE(rt.scheduled_departure_time, st.scheduled_departure_time) as "scheduled_departure_time", rt.predicted_arrival_time as "predicted_arrival_time", rt.predicted_departure_time as "predicted_departure_time", rt.predicted_arrival_uncertainty as "predicted_arrival_uncertainty", rt.predicted_departure_uncertainty as "predicted_departure_uncertainty", rt.schedule_relationship as "schedule_relationship", COALESCE(rt.stop_headsign, st.stop_headsign) as "stop_headsign", COALESCE(rt.pickup_type, st.pickup_type) as "pickup_type", COALESCE(rt.drop_off_type, st.drop_off_type) as "drop_off_type", rt.last_updated_at as "last_updated_at" from transit.stop_time_realtime_instances rt full join transit.stop_time_static_instances st on rt.trip_instance_id = st.trip_instance_id AND (
                CASE WHEN rt.stop_id IS NOT NULL
                    THEN rt.stop_id = st.stop_id
                    ELSE rt.stop_sequence = st.stop_sequence
                END
            ));